                    </div>
                    {maps.map((m, mi) => {
                      const pct   = parsePct(m.confidence);
                      const sem   = colSemMap[m.sourceField];
                      const role  = sem?.semantic_role || 'unknown';
                      return (
                        <div key={mi} className="dr-map-row">
