        const agentResponse = await e2etraceFetchWithRetry(`${API_CONFIG?.API_BASE_URL || ''}/api/agentic/task`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
             type: "data_discovery",
             required_capabilities: ["perform_data_discovery", "discover_files"],
             payload: {
               type: "discovery",
