// ΓöÇΓöÇΓöÇ Helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function fmtDate(iso) {
  if (!iso) return 'ΓÇö';
  return new Date(iso).toLocaleString();
}
function fmtRelative(iso) {
  if (!iso) return '';
  const diff = Date.now() - new Date(iso).getTime();
  const m = Math.floor(diff / 60000);
  if (m < 1) return 'just now';
  if (m < 60) return `${m}m ago`;
  const h = Math.floor(m / 60);
  if (h < 24) return `${h}h ago`;
  return `${Math.floor(h / 24)}d ago`;
}
function typeMeta(t) { return TYPE_META[t] || { label: t, icon: 'fas fa-file-alt', color: '#94a3b8', page: null }; }
function statusBadge(s) {
  const m = STATUS_META[s] || { label: s, color: '#94a3b8', bg: '#f1f5f9' };
  return (
    <span className="rh-status-badge" style={{ color: m.color, background: m.bg }}>
      {m.label}
    </span>
  );
}

// ΓöÇΓöÇΓöÇ Export helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function downloadBlob(blob, filename) {
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  setTimeout(() => URL.revokeObjectURL(url), 150);
}

// Fetch the full report (with `result` payload) on demand. The list endpoint
// only returns `summary`, so without this hydration any export is incomplete.
async function hydrateReport(report) {
  if (report && report.result !== undefined && report.result !== null) {
    return report;
  }
  if (!report?.report_id) return report;
  try {
    const url = `${API_CONFIG.API_BASE_URL}${API_CONFIG.ENDPOINTS.REPORT_HUB}/${encodeURIComponent(report.report_id)}`;
    const r = await fetch(url);
    if (!r.ok) return report;
    const full = await r.json();
    return { ...report, ...full };
  } catch {
    return report;
  }
}

async function exportReportAsJSON(report) {
  const full = await hydrateReport(report);
  const payload = {
    report_id: full.report_id,
    report_type: full.report_type,
    title: full.title,
    status: full.status,
    workflow_id: full.workflow_id,
    run_id: full.run_id,
    source_page: full.source_page,
    tags: full.tags,
    created_at: full.created_at,
    summary: full.summary,
    result: full.result ?? null,
  };
  const blob = new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json' });
  const safe = (full.title || full.report_id).replace(/[^a-z0-9_-]/gi, '_').slice(0, 60);
  downloadBlob(blob, `report-${safe}-${Date.now()}.json`);
}

// Recursively flatten nested objects/arrays into dotted-key rows.
function flattenForCsv(value, prefix, out) {
  if (value === null || value === undefined) {
    out.push([prefix, '']);
    return;
  }
  if (Array.isArray(value)) {
    if (value.length === 0) {
      out.push([prefix, '[]']);
      return;
    }
    const allPrimitive = value.every((v) => v === null || ['string', 'number', 'boolean'].includes(typeof v));
    if (allPrimitive) {
      out.push([prefix, value.join('; ')]);
      return;
    }
    value.forEach((v, i) => flattenForCsv(v, `${prefix}[${i}]`, out));
    return;
  }
  if (typeof value === 'object') {
    const keys = Object.keys(value);
    if (keys.length === 0) {
      out.push([prefix, '{}']);
      return;
    }
    keys.forEach((k) => flattenForCsv(value[k], prefix ? `${prefix}.${k}` : k, out));
    return;
  }
  out.push([prefix, String(value)]);
}

async function exportReportAsCSV(report) {
  const full = await hydrateReport(report);
  const rows = [['Field', 'Value']];
  rows.push(['report_id', full.report_id ?? '']);
  rows.push(['report_type', full.report_type ?? '']);
  rows.push(['title', full.title ?? '']);
  rows.push(['status', full.status ?? '']);
  rows.push(['workflow_id', full.workflow_id ?? '']);
  rows.push(['run_id', full.run_id ?? '']);
  rows.push(['created_at', full.created_at ?? '']);
  if (full.summary && typeof full.summary === 'object') {
    flattenForCsv(full.summary, 'summary', rows);
  }
  if (full.result && typeof full.result === 'object') {
    flattenForCsv(full.result, 'result', rows);
  }
  const csv = rows.map((r) => r.map((c) => {
    const s = String(c);
    return /[\n\r,"]/.test(s) ? `"${s.replace(/"/g, '""')}"` : s;
  }).join(',')).join('\n');
  const blob = new Blob([csv], { type: 'text/csv;charset=utf-8' });
  const safe = (full.title || full.report_id).replace(/[^a-z0-9_-]/gi, '_').slice(0, 60);
  downloadBlob(blob, `report-${safe}-${Date.now()}.csv`);
}

function exportReportsListAsJSON(reportsList) {
  const blob = new Blob(
    [JSON.stringify({ exported_at: new Date().toISOString(), count: reportsList.length, reports: reportsList }, null, 2)],
    { type: 'application/json' }
  );
  downloadBlob(blob, `reports-export-${Date.now()}.json`);
}

function exportReportsListAsCSV(reportsList) {
  const headers = ['report_id', 'report_type', 'title', 'status', 'workflow_id', 'run_id', 'source_page', 'tags', 'created_at'];
  const rows = [headers, ...reportsList.map((r) => [
    r.report_id ?? '', r.report_type ?? '', r.title ?? '', r.status ?? '',
    r.workflow_id ?? '', r.run_id ?? '', r.source_page ?? '',
    (r.tags || []).join('; '), r.created_at ?? '',
  ])];
  const csv = rows.map((r) => r.map((c) => {
    const s = String(c);
    return /[\n\r,"]/.test(s) ? `"${s.replace(/"/g, '""')}"` : s;
  }).join(',')).join('\n');
  const blob = new Blob([csv], { type: 'text/csv;charset=utf-8' });
  downloadBlob(blob, `reports-export-${Date.now()}.csv`);
}

