        <TypePill type="" count={reports.length} active={filterType === ''} onClick={() => setFilterType('')} />
        {byTypeCounts.map(([t, n]) => (
          <TypePill key={t} type={t} count={n} active={filterType === t} onClick={() => setFilterType(filterType === t ? '' : t)} />
